students = {
    "alice": {"age": 25, "grade": "A"},
    "bob": {"age": 22, "grade": "B"}
}

print("Alice's grade:", students["alice"]["grade"])

# Loop through
for name, info in students.items():
    print(f"\n{name}:")
    for key, value in info.items():
        print(f"  {key}: {value}")
